import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Deep Linking Full Reference","description":"","frontmatter":{"title":"Deep Linking Full Reference","slug":"deep-link-reference"},"headers":[],"relativePath":"marketer-hub/deep-link-reference.md","filePath":"marketer-hub/deep-link-reference.md"}'),n={name:"marketer-hub/deep-link-reference.md"};function r(d,e,s,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>You can use deep links for your Journeys, Ads Links, Short Links, and Email. Use this reference article to help you configure your default and custom link behavior.</p><p>Read our <a href="./create-web-links.html">Create Web Links</a> or <a href="./create-app-links.html">Create App Links</a> articles for instructional content on creating links using different methods.</p><p>In this reference article, you can learn about:</p><ul><li><a href="./deep-link-reference.html#create-deep-links">Creating deep links</a></li><li><a href="./deep-link-reference.html#validate-deep-link-behavior">Validating deep link behavior</a></li><li><a href="./deep-link-reference.html#configure-deep-links">Configuring deep links</a></li><li><a href="./deep-link-reference.html#read-deep-links">Reading deep links</a></li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Information about web links in this article is only relevant for the Engagement product, read our <a href="./create-web-links.html">Create Web Links</a> article for web links information relevant to the Activation product.</p></div><h2 id="create-deep-links" tabindex="-1">Create deep links <a class="header-anchor" href="#create-deep-links" aria-label="Permalink to &quot;Create deep links&quot;">​</a></h2><p>You can create both web and app deep links with the Branch Growth Platform. Links can be either short or long.</p><h3 id="short-links" tabindex="-1">Short Links <a class="header-anchor" href="#short-links" aria-label="Permalink to &quot;Short Links&quot;">​</a></h3><p>Short Links are the most common deep links created with the Branch SDK or Deep Linking API. You can use a Branch-provided <code>app.link</code>, or use a custom domain (for example, <code>links.yoursite.com</code>). You can also tailor the appearance of the shortcode to a custom <code>alias</code> during creation. Aliases can be short strings (for example, <code>https://example.app.link/october-sale</code>), or can be a full link path (for example, <code>https://example.app.link/product/id1234</code> ).</p><p>Short Links contain <a href="./deep-link-reference.html#configure-deep-links">link data</a> inside them on link creation (for example, existing link <code>https://example.app.link/fzmLEhobLD</code> ). Short Links can also have additional data appended to them (for example, dynamic link <code>https://example.app.link/fzmLEhobLD?content_id=123</code> ).</p><h4 id="methods-of-creating-short-links" tabindex="-1">Methods of creating Short Links <a class="header-anchor" href="#methods-of-creating-short-links" aria-label="Permalink to &quot;Methods of creating Short Links&quot;">​</a></h4><p>Check out our <a href="./create-web-links.html">Create Web Links</a> and <a href="./create-app-links.html">Create App Links</a> articles to learn more about creating Short Links.</p><h3 id="long-links" tabindex="-1">Long links <a class="header-anchor" href="#long-links" aria-label="Permalink to &quot;Long links&quot;">​</a></h3><p>Long links can be created without a network call to Branch. Long links need <a href="./deep-link-reference.html#configure-deep-links">link data</a> to be added as a query string. Be sure to URI encode any URLs in the link.</p><ul><li>Existing link example: <code>https://example.app.link/fzmLEhobLD?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code> or</li><li>Dynamic link example: <code>https://example.app.link/?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code> .</li></ul><p>Long links need a <code>/a/</code> and a <a href="./profile-settings.html">Branch Key</a> if you use a custom domain.</p><ul><li>Existing link example: <code>https://link.example.com/5NPh/p4M09KRLrD?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code></li><li>Dynamic link example: <code>https://link.example.com/a/key_live_kaFuWw8WvY7yn1d9yYiP8gokwqjV0Swt?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code></li></ul><p>When adding <code>tags</code> to a dynamic link, enter each tag separately. For example: <code>https://example.app.link/?foo=bar&amp;~tags=tag1&amp;~tags=tag2</code></p><h2 id="validate-deep-link-behavior" tabindex="-1">Validate deep link behavior <a class="header-anchor" href="#validate-deep-link-behavior" aria-label="Permalink to &quot;Validate deep link behavior&quot;">​</a></h2><p>Use the <a href="./link-validator.html">Link Validator</a> to view the expected and actual behavior of your links.</p><details><summary>Expand to view information about expected link behaviors</summary><h4 id="default-link-behavior" tabindex="-1">Default link behavior <a class="header-anchor" href="#default-link-behavior" aria-label="Permalink to &quot;Default link behavior&quot;">​</a></h4><p>If your user <strong>does not</strong> have your app installed:</p><ol><li><p>User <code>clicks</code> on a Branch deep link.</p></li><li><p>Device <code>navigates</code> to the <a href="./deep-link-reference.html#link-behavior-and-redirects">fallback</a> (for example, an app store or website).</p><ul><li><p>We support the following app stores:</p><ul><li>Apple App Store</li><li>Google Play</li><li>Huawei App Store</li><li>Vivo App Store</li><li>Oppo App Store</li><li>Baidu Mobile Assistant</li></ul></li></ul></li><li><p>User <code>installs</code> and <code>opens</code> your app.</p></li><li><p>Branch passes deep link <code>data</code> into your app.</p></li></ol><p>If your user <strong>does</strong> have your app installed:</p><ol><li>User <code>clicks</code> on a Branch deep link.</li><li>Device <code>opens</code> your app or navigates to <a href="./deep-link-reference.html#link-behavior-and-redirects">expected link behavior</a>.</li><li>Branch passes deep link <code>data</code> into your app.</li></ol><h4 id="custom-link-behavior" tabindex="-1">Custom link behavior <a class="header-anchor" href="#custom-link-behavior" aria-label="Permalink to &quot;Custom link behavior&quot;">​</a></h4><p><strong>Pass data from link to app</strong></p><ol><li>Add <a href="./deep-link-reference.html#configure-deep-links">link data</a> to each deep link.</li><li>Add key-values pairs to your Short Links.</li><li>Append query strings <code>https://example.app.link/fzmLEhobLD?$custom_data=123&amp;hello=world</code> .</li></ol><p><strong>Fallback to a specific URL</strong></p><ul><li><p>Determine where a deep link will navigate to if either</p><ul><li>Your app is not installed</li><li><em>[or]</em> Another app prevent links from deep linking outside their app</li></ul></li><li><p>Fallback overrides <em>(ordered by precedence)</em></p><ul><li>Add query string <code>https://example.app.link?$ios_url=https://example.com</code></li><li>Add link data <code>$ios_url = &#39;https://example.com&#39;</code> (<a href="./deep-link-reference.html#link-behavior-and-redirects">docs</a>)</li><li>Add link data for a deep view <code>$ios_deepview = &#39;deepviewId&#39;</code> (<a href="./enable-deepviews.html">docs</a>)</li><li>Enable a <strong>Deep View</strong> globally on the <a href="https://dashboard.branch.io/web/deepviews" target="_blank" rel="noreferrer">Branch Dashboard</a></li><li>Add link data <code>$fallback_url = &#39;https://example.com&#39;</code> (<a href="./deep-link-reference.html#link-behavior-and-redirects">docs</a>)</li><li>Add <code>iOS/Android Custom URL</code> on the <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">Branch Dashboard</a></li><li>Add <strong>Default URL</strong> (<code>$fallback_url</code>) on the <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">Branch Dashboard</a></li></ul></li></ul><p><strong>Open</strong> <strong>web</strong> <strong>instead of app</strong></p><p>This information is only relevant to the <a href="./packaging.html">Engagement product</a>. <a href="./packaging.html#activation-product">Activation</a> links do not require /e/ or -web to open in a web browser.</p><p>If your app is not installed: device <code>navigates</code> to the <a href="./deep-link-reference.html#link-behavior-and-redirects">fallback</a> (for example, an app store or website).</p><p>If your app is installed:</p><ul><li><ul><li><p><em>iOS:</em> need to override <code>Universal Links</code></p><ul><li><p>Add <code>$web_only = true</code> (<a href="./deep-link-reference.html#link-behavior-and-redirects">docs</a>).</p></li><li><p>Add redirect <code>$ios_url = &#39;https://google.com&#39;</code> (<a href="./deep-link-reference.html#redirections">docs</a>).</p></li><li><p><em>[or]</em> Append <code>/e/</code> to the deep link.</p><ul><li>e.g. <code>https://example.app.link/fzmLEhobLD</code> -&gt; <code>https://example.app.link/e/fzmLEhobLD</code></li></ul></li></ul></li><li><p><em>Android:</em> need to override <code>App Links</code></p><ul><li>Uncheck <code>Enable App Links</code> and then hit <code>Save</code> on the <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Add redirect <code>$android_url = &#39;https://google.com&#39;</code> (<a href="./deep-link-reference.html#redirections">docs</a>).</li><li>Add a broken URI Scheme with <code>$android_deeplink_path = &#39;random&#39;</code> .</li></ul></li></ul></li><li><p>Add <code>-web</code> in the link domain: e.g. <code>branch.app.link</code> -&gt; <code>branch-web.app.link</code> .</p><ul><li>Does not work with custom link domains when used in conjunction with a custom alias.</li></ul></li></ul><h4 id="social-link-behavior" tabindex="-1">Social link behavior <a class="header-anchor" href="#social-link-behavior" aria-label="Permalink to &quot;Social link behavior&quot;">​</a></h4><ul><li><p>Use <a href="./deep-link-reference.html#open-graph">OG Tags</a> to display content as a preview card in Facebook, Twitter, Pinterest, iMessage, etc.</p><ul><li>The <code>$og_title</code> and <code>$og_description</code> tags are included with the Branch Growth Platform.</li><li>The <code>$og_image_url</code> tag is reserved for paid Branch accounts with a dedicated contract.</li></ul></li><li><p>Use <a href="./deepviews.html">Deepviews</a> to display content as a website.</p><ul><li>Increases install attribution.</li><li>Completes deep linking experience in <a href="./deep-link-reference.html#link-behavior-and-redirects">certain apps</a>.</li></ul></li></ul><h4 id="utm-behavior" tabindex="-1">UTM behavior <a class="header-anchor" href="#utm-behavior" aria-label="Permalink to &quot;UTM behavior&quot;">​</a></h4><p>This is enabled by default. To disable this functionality, go to <strong>Link Settings</strong> &gt; <strong>Advance Settings</strong> &gt; <strong>Analytics mapping with UTM</strong>.</p><ul><li><p>When redirecting to a web URL, Branch automatically passes through any values from the following Branch link analytics tags as UTM parameters:</p><ul><li><code>~campaign</code> -&gt; <code>utm_campaign</code></li><li><code>~channel</code> -&gt; <code>utm_source</code></li><li><code>~feature</code> -&gt; <code>utm_medium</code></li></ul></li><li><p>This applies to web URLs defined using any of the following <code>$fallback_url</code>, <code>$ios_url</code>, <code>$android_url</code>, <code>$desktop_url</code>, <code>$original_url</code>, and <code>$canonical_url</code>.</p></li><li><p>If these UTM parameters are already detected on the URLs being redirected to, Branch will not overwrite them.</p></li><li><p>For more information about UTM parameters, please read Google Analytic&#39;s <a href="https://support.google.com/analytics/answer/1033863" target="_blank" rel="noreferrer">Custom Campaigns</a> article.</p></li></ul><h4 id="expiration-behavior" tabindex="-1">Expiration behavior <a class="header-anchor" href="#expiration-behavior" aria-label="Permalink to &quot;Expiration behavior&quot;">​</a></h4><p>The default expiration behavior will vary depending on the type of Branch Link you&#39;re using.</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Expiration</th></tr></thead><tbody><tr><td>Short Links</td><td>Starting March 11, 2024. Expires 380 Days after creation. This expiration window is reset when the Short Link is clicked or if Branch receives a <a href="./readexistingdeeplink.html">read request via the Deep Linking API</a>.</td></tr><tr><td>Long Links</td><td>Does not expire</td></tr><tr><td>Short Links</td><td>Does not expire</td></tr><tr><td>Ad Links</td><td>Does not expire</td></tr></tbody></table></details><h2 id="configure-deep-links" tabindex="-1">Configure deep links <a class="header-anchor" href="#configure-deep-links" aria-label="Permalink to &quot;Configure deep links&quot;">​</a></h2><p>You can add any of your own key-value parameters to a Branch link. These parameters will be passed to your app via the Branch SDK, however some keys will have specific extra effects.</p><h3 id="link-data" tabindex="-1">Link data <a class="header-anchor" href="#link-data" aria-label="Permalink to &quot;Link data&quot;">​</a></h3><p>Specify where to deep link users in your app, or configure advanced settings like device-based targeting, attribution windows, and custom keys specific to your app.</p><h4 id="popular" tabindex="-1">Popular <a class="header-anchor" href="#popular" aria-label="Permalink to &quot;Popular&quot;">​</a></h4><p>The most popular and commonly used data options.</p><table tabindex="0"><thead><tr><th>Name</th><th>Default value</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>Deep Link Path</td><td><code>open?link_click_id=1234</code></td><td><code>$deeplink_path</code></td><td>Sets a default deep link path for all platforms. When a user opens a Branch Link with this parameter, the Branch SDK will route them to the specified in-app content path.</td></tr><tr><td>iOS Deep Link Path</td><td></td><td><code>$ios_deeplink_path</code></td><td>Sets the deep link path for iOS apps, which overrides the default path. When a user on an iOS device opens a Branch Link, the Branch SDK will route them to the specified in-app content path.</td></tr><tr><td>Android Deep Link Path</td><td></td><td><code>$android_deeplink_path</code></td><td>Sets the deep link path for Android apps. When the Branch SDK receives a link with this parameter set, it will automatically load the custom Android URI path contained within.</td></tr><tr><td>Fallback URL</td><td></td><td><code>$fallback_url</code></td><td>Change the redirect destination for all platforms so you don’t have to enable it by platform. Branch will forward all robots to this URL, which overrides any OG tags entered in the link. System-wide default URL (set in Link Settings).</td></tr><tr><td>Canonical URL</td><td></td><td><code>$canonical_url</code></td><td>The corresponding web URL for the in-app content.</td></tr><tr><td>Unique Content Identifier</td><td></td><td><code>$canonical_identifier</code></td><td>This is the unique identifier for content that will help Branch dedupe across many instances of the same thing. Suitable options include a website with pathing, or a database with identifiers for entities.</td></tr><tr><td>iOS Passive Deepview Template</td><td><code>branch_default</code></td><td><code>$ios_passive_deepview</code></td><td>The name of the Deepview template that your link will fallback to for iOS.</td></tr><tr><td>Android Passive Deepview Template</td><td><code>branch_default</code></td><td><code>$android_passive_deepview</code></td><td>The name of the Deepview template that your link will fall back to for Android.</td></tr><tr><td>Always Deep Link to App</td><td><code>true</code></td><td><code>$always_deeplink</code></td><td>Set to false to make links always fall back to your mobile site. Does not apply to Universal Links or Android App Links.</td></tr><tr><td>Deep Linking Window (Seconds)</td><td><code>7200</code></td><td><code>$match_duration</code></td><td>Lets you control the snapshotting match timeout (the time that a click will wait for an app open to match), also known as attribution window. Specified in seconds.</td></tr><tr><td>URI Redirect Mode</td><td></td><td><code>$uri_redirect_mode</code></td><td>Allows you to control how and when Branch uses URI schemes to open your app.</td></tr><tr><td>iOS URI Redirect Mode</td><td></td><td><code>$ios_uri_redirect_mode</code></td><td>Allows you to control how and when Branch uses URI schemes to open your app on iOS.</td></tr><tr><td>Android URI Redirect Mode</td><td></td><td><code>$android_uri_redirect_mode</code></td><td>Allows you to control how and when Branch uses URI schemes to open your app on Android.</td></tr></tbody></table><h4 id="deep-linking-parameters" tabindex="-1">Deep linking parameters <a class="header-anchor" href="#deep-linking-parameters" aria-label="Permalink to &quot;Deep linking parameters&quot;">​</a></h4><p>Set the specific in-app content a user is routed to.</p><table tabindex="0"><thead><tr><th>Name</th><th>Default value</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>Deep Link Path</td><td><code>open?link_click_id=1234</code></td><td><code>$deeplink_path</code></td><td>Sets a default deep link path for all platforms. When a user opens a Branch Link with this parameter, the Branch SDK will route them to the specified in-app content path.</td></tr><tr><td>iOS Deep Link Path</td><td></td><td><code>$ios_deeplink_path</code></td><td>Sets the deep link path for iOS apps, which overrides the default path. When a user on an iOS device opens a Branch Link, the Branch SDK will route them to the specified in-app content path.</td></tr><tr><td>Android Deep Link Path</td><td></td><td><code>$android_deeplink_path</code></td><td>Sets the deep link path for Android apps. When the Branch SDK receives a link with this parameter set, it will automatically load the custom Android URI path contained within.</td></tr><tr><td>Desktop Deep Link Path</td><td></td><td><code>$desktop_deeplink_path</code></td><td>Sets the deep link path for desktop apps. You must fetch this parameter from the link to route the user to the correct destination.</td></tr></tbody></table><h4 id="link-behavior-and-redirects" tabindex="-1">Link behavior and redirects <a class="header-anchor" href="#link-behavior-and-redirects" aria-label="Permalink to &quot;Link behavior and redirects&quot;">​</a></h4><p>Set where to send users if the app cannot be opened (for example, if it is not installed).</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Using redirect parameters on Branch Links requires a valid credit card to be entered on your account. Alternatively, you can set up an Enterprise account.</p></div><details><summary>Expand to view information about forced redirects</summary><h3 id="forced-redirections" tabindex="-1">Forced Redirections <a class="header-anchor" href="#forced-redirections" aria-label="Permalink to &quot;Forced Redirections&quot;">​</a></h3><p>Prevent error messages from other apps when Branch deep links are clicked.</p><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Usage</th></tr></thead><tbody><tr><td><code>$uri_redirect_mode</code></td><td><strong>0</strong></td><td>Conservative mode. We don&#39;t try to open the app if the user can see an error.</td></tr><tr><td><code>$uri_redirect_mode</code></td><td><strong>1</strong></td><td>Smart redirect mode. This is the default value that yields the same behavior as 0 until we know the user has the app installed through Branch persona data. In that case, force URI schemes to open the app.</td></tr><tr><td><code>$uri_redirect_mode</code></td><td><strong>2</strong></td><td>Forceful redirect mode. Always try to force open the app, even if it risks showing an <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/uri-error-message(1).png" target="_blank" rel="noreferrer">error message</a> when the app is not installed.</td></tr></tbody></table><ul><li><p>Forced redirections will not force open the app when the link is configured with an &quot;Active Deepview&quot; or &quot;NativeLink&quot; since they are intended to load a webpage and not redirect elsewhere.</p></li><li><p>OS level redirect modes can be enabled by utilizing the parameters <code>$ios_uri_redirect_mode</code> and <code>$android_uri_redirect_mode</code>.</p></li><li><p>Supported Apps</p><ul><li>Facebook newsfeed iOS</li><li>Instagram iOS</li><li>Twitter iOS</li><li>Safari iOS</li><li>Firefox iOS &amp; Android</li></ul></li></ul></details><table tabindex="0"><thead><tr><th>Name</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>Fallback URL</td><td><code>$fallback_url</code></td><td>Sets a single fallback URL for all platforms where users are redirected if the app cannot be opened or if they do not have the app downloaded. If the link is a web-only link, this will be the destination. <strong>Note</strong>: Branch forwards all web crawlers (robots) to this URL, which overrides any Open Graph (OG) tags you set.</td></tr><tr><td>Country-Specific Fallback URL</td><td><code>$fallback_url_xx</code></td><td>Change the redirect endpoint for all platforms based on a <a href="https://www.iso.org/obp/ui/#search" target="_blank" rel="noreferrer">lower-case Alpha-2 country code</a>. For example, <code>$fallback_url_de=&quot;...&quot;</code> would redirect Germany deep link clicks. You should also set <code>$fallback_url</code> to act as the global redirect in addition to the country-specific ones. <strong>Warning</strong>: If platform-specific redirects (like <code>$ios_url</code> or <code>$desktop_url</code>) are set, they will override the country-specific redirect. We recommend you only use $fallback_url_xx for the country-specific redirects and <code>$fallback_url</code> to catch all other users.</td></tr><tr><td>iPad Redirect URL</td><td><code>$ipad_url</code></td><td>Sets a specific redirect URL for iPad users, overriding the <code>$ios_url</code> value.</td></tr><tr><td>Samsung Galaxy Store Redirect URL</td><td><code>$samsung_url</code></td><td>Redirect users on Samsung devices to the Samsung Galaxy Store. You must provide the link in the following format: <code>http://www.samsungapps.com/appquery/appDetail.as?appId=YOUR.PACKAGE.NAME</code></td></tr><tr><td>Huawei App Gallery URL</td><td><code>$huawei_url</code></td><td>Redirect users on Huawei devices to the Huawei AppGallery. The URL format must following Huawei’s App Linking guide.</td></tr><tr><td>Force Web Open</td><td><code>$web_only</code></td><td>Forces the link to open the web URL set in <code>$fallback_url</code> instead of opening the app.</td></tr><tr><td>Mobile Web Only (Desktop App)</td><td><code>$mobile_web_only</code></td><td>When set to <code>true</code>, the link will open your website on mobile devices but will open the app on desktop.</td></tr><tr><td>Desktop Web Only (Mobile App)</td><td><code>$desktop_web_only</code></td><td>When set to <code>true</code>, the link will open your website on desktop but will open the app on mobile devices.</td></tr><tr><td>Always Deep Link to App</td><td><code>$always_deeplink</code></td><td>Set to <code>false</code> to make links always fall back to your mobile site. Does not apply to Universal Links or Android App Links.</td></tr><tr><td>Enable iOS NativeLink</td><td><code>$ios_nativelink</code></td><td>When set to true, the link routes through NativeLink to enable deferred deep linking for iOS 15+ and Private Relay users.</td></tr><tr><td>URI Redirect Mode</td><td><code>$uri_redirect_mode</code></td><td>Allows you to control how and when Branch uses URI schemes to open your app.</td></tr><tr><td>iOS URI Redirect Mode</td><td><code>$ios_uri_redirect_mode</code></td><td>Allows you to control how and when Branch uses URI schemes to open your app on iOS.</td></tr><tr><td>Android URI Redirect Mode</td><td><code>$android_uri_redirect_mode</code></td><td>Allows you to control how and when Branch uses URI schemes to open your app on Android.</td></tr><tr><td>iOS App Store Redirect Delay (Milliseconds)</td><td><code>$ios_redirect_timeout</code></td><td>Control the timeout that the client-side JS waits after trying to open up the app before redirecting to the App Store. Specified in milliseconds.</td></tr><tr><td>Android Play Store Redirect Delay (Milliseconds)</td><td><code>$android_redirect_timeout</code></td><td>Control the timeout that the client-side JS waits after trying to open up the app before redirecting to the Play Store. Specified in milliseconds.</td></tr></tbody></table><h4 id="attribution-and-analytics-control" tabindex="-1">Attribution and analytics control <a class="header-anchor" href="#attribution-and-analytics-control" aria-label="Permalink to &quot;Attribution and analytics control&quot;">​</a></h4><p>Control the time window during which installs, opens, or conversions can be attributed to a link click or impression.</p><table tabindex="0"><thead><tr><th>Name</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>Click-to-Install Window (Days)</td><td><code>$click_install_window_days</code></td><td>Time between a click and an install or reinstall. For example: <code>.../?$click_install_window_days=3</code></td></tr><tr><td>Click-to-Open/Session Window (Days)</td><td><code>$click_session_start_window_days</code></td><td>Time between a click and an open or web session start. For example: <code>.../?$click_session_start_window_days=7</code></td></tr><tr><td>Click-to-Conversion Window (Days)</td><td><code>$click_conversion_window_days</code></td><td>Time between a click and a conversion event. Conversion events include commerce events, all custom events, and all view events. For example: <code>.../?$click_conversion_window_days=30</code></td></tr><tr><td>Impression-to-Install Window (Days)</td><td><code>$impression_install_window_days</code></td><td>Time between an ad impression and an install and reinstall. For example: <code>.../?$impression_install_window_days=3</code></td></tr><tr><td>Impression-to-Open/Session Window (Days)</td><td><code>$impression_session_start_window_days</code></td><td>Time between an ad impression and an open or web session start. For example: <code>.../?$impression_session_start_window_days=1</code></td></tr><tr><td>Impression-to-Conversion Window (Days)</td><td><code>$impression_conversion_window_days</code></td><td>Time between an ad impression and a conversion event. Conversion events include commerce events, all custom events, and all view events. For example: <code>.../?$impression_conversion_window_days=7</code></td></tr><tr><td>Deep Linking Window (Seconds)</td><td><code>$match_duration</code></td><td>Lets you control the snapshotting match timeout (the time that a click will wait for an app open to match), also known as attribution window. Specified in seconds.</td></tr><tr><td>Deep Link Only (No Attribution)</td><td><code>$deeplink_no_attribution</code></td><td>Set to true for the links to only support deep linking without any attribution for that link. <strong>Note</strong>: Using this will lose all link metrics when set to <code>true</code>.</td></tr><tr><td>Disable Click Tracking &amp; Analytics</td><td><code>$do_not_process</code></td><td>This will prevent click tracking and storage of link analytics. Deep link data will still flow into the app from link click to app open.</td></tr></tbody></table><p><strong>Analytical data keys</strong></p><p>These labels allow you to filter and organize your deep links. Refer to the “Reserved prefixes” section of this article to learn more about the <code>~</code> prefix.</p><table tabindex="0"><thead><tr><th>Key</th><th>Usage</th></tr></thead><tbody><tr><td><code>~channel or channel</code></td><td>Use channel to tag the route that your link reaches users. For example, tag links with <code>&#39;Facebook&#39;</code> or <code>&#39;LinkedIn&#39;</code> to help track clicks and installs through those paths separately</td></tr><tr><td><code>~feature or feature</code></td><td>This is the feature of your app that the link might be associated with. For example, if you had built a referral program, you would label links with the feature &#39;referral&#39;</td></tr><tr><td><code>~campaign or campaign</code></td><td>Use this field to organize the links by actual campaign. For example, if you launched a new feature or product and want to run a campaign around that</td></tr><tr><td><code>~campaign_id</code></td><td>Use this field to organize the links by actual campaign id. For example, if you launched a new feature or product and want to run a campaign around that</td></tr><tr><td><code>~customer_campaign</code></td><td>The customer campaign specified for the last attributed touch. can be specified on links by the client.</td></tr><tr><td><code>~stage</code></td><td>Use this to categorize the progress or category of a user when the link was generated. For example, if you had an invite system accessible on level 1, level 3 and 5, you could differentiate links generated at each level with this parameter</td></tr><tr><td><code>~tags or tags</code></td><td>This is a free form entry with unlimited values <code>[&#39;string&#39;]</code>. Use it to organize your link data with labels that don&#39;t fit within the bounds of the above</td></tr><tr><td><code>~secondary_publisher</code></td><td>secondary publisher specified for the last attributed touch. passed by the ad network.</td></tr><tr><td><code>~customer_secondary_publisher</code></td><td>The ID of the secondary publisher specified for the last attributed touch. can be specified on links by the client.</td></tr><tr><td><code>~creative_name</code></td><td>The creative name specified for the last attributed touch.</td></tr><tr><td><code>~creative_id</code></td><td>The creative ID specified for the last attributed touch.</td></tr><tr><td><code>~ad_set_name</code></td><td>The ad set name specified for the last attributed touch.</td></tr><tr><td><code>~ad_set_id</code></td><td>The ad set ID specified for the last attributed touch.</td></tr><tr><td><code>~customer_ad_set_name</code></td><td>The customer ad set name specified for the last attributed touch. can be specified on links by the client.</td></tr><tr><td><code>~ad_name</code></td><td>The ad name specified for the last attributed touch.</td></tr><tr><td><code>~ad_id</code></td><td>The ad ID specified for the last attributed touch.</td></tr><tr><td><code>~customer_ad_name</code></td><td>The customer ad name specified for the last attributed touch. can be specified on the link by the client.</td></tr><tr><td><code>~keyword</code></td><td>The keyword specified for the last attributed touch.</td></tr><tr><td><code>~keyword_id</code></td><td>The unique ID for keyword of the last touch</td></tr><tr><td><code>~customer_keyword</code></td><td>The customer keyword of the last touch. Can be specified on links by the client.</td></tr><tr><td><code>~placement</code></td><td>The placement of the last touch, as set with an analytics tag. Actual app or website the ad appears on display campaigns.</td></tr><tr><td><code>~placement_id</code></td><td>The ID of placement of the last touch, as set with an analytics tag. Actual app or website the ad appears on display campaigns.</td></tr><tr><td><code>~customer_placement</code></td><td>The customer specified placement of the last touch, as set with an analytics tag. Actual app or website the ad appears on display campaigns. Can be specified on the link by the client.</td></tr><tr><td><code>~sub_site_name</code></td><td>Reference to the site where the ad was displayed.</td></tr><tr><td><code>~customer_sub_site_name</code></td><td>Customer reference to the site where the ad was displayed. Can be specified on links by the client.</td></tr></tbody></table><h4 id="social-media-previews" tabindex="-1">Social media previews <a class="header-anchor" href="#social-media-previews" aria-label="Permalink to &quot;Social media previews&quot;">​</a></h4><p>Customize how a link preview appears when shared on social media platforms.</p><table tabindex="0"><thead><tr><th>Name</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>Social Media Image Width</td><td><code>$og_image_width</code></td><td>Set the image’s width in pixels for social media previews.</td></tr><tr><td>Social Media Image Height</td><td><code>$og_image_height</code></td><td>Set the image’s heigh in pixels for social media previews.</td></tr><tr><td>Social Media Video URL</td><td><code>$og_video</code></td><td>Set a video as it will be seen in social media previews.</td></tr><tr><td>Social Media Base URL</td><td><code>$og_url</code></td><td>Set the base URL of the link as it will be seen in social media previews.</td></tr><tr><td>Social Media Card Type</td><td><code>$og_type</code></td><td>Set the type of custom card format link as it will be seen in social media previews. Don’t set this property when sharing deep links on Facebook.</td></tr><tr><td>Social Media App ID</td><td><code>$og_app_id</code></td><td>Set the app ID tag.</td></tr><tr><td>Advanced Social Media Redirect</td><td><code>$og_redirect</code></td><td>Advanced, not recommended for most use cases. Set a custom URL that we redirect social media bots to in order to retrieve all the appropriate tags.</td></tr><tr><td>Twitter (X) Card Type</td><td><code>$twitter_card</code></td><td>Set the Twitter card type of the link (for example, player). You must allowlist your deep link with the Twitter Card Validator.</td></tr><tr><td>Twitter (X) Site Name</td><td><code>$twitter_site</code></td><td>Set the site for Twitter (X).</td></tr><tr><td>Twitter (X) App Country</td><td><code>$twitter_app_country</code></td><td>Set the app country for the app card.</td></tr><tr><td>Twitter (X) Video Player URL</td><td><code>$twitter_player</code></td><td>Set the video player’s URL. Default to the video value of <code>$og_video</code>.</td></tr><tr><td>Twitter (X) Player Width</td><td><code>$twitter_player_width</code></td><td>Set the player’s width in pixels.</td></tr><tr><td>Twitter (X) Player Height</td><td><code>$twitter_player_height</code></td><td>Set the player’s height in pixels.</td></tr><tr><td>Custom Social Media Meta Tags</td><td><code>$custom_meta_tags</code></td><td>Valid string JSON dictionary of the tags’ keys and values. For example: <code>{&quot;twitter:player:stream&quot;: &quot;https://branch.io&quot;}</code></td></tr></tbody></table><h4 id="content-metadata" tabindex="-1">Content metadata <a class="header-anchor" href="#content-metadata" aria-label="Permalink to &quot;Content metadata&quot;">​</a></h4><p>Set the content the link points to, helping with organization, deduplication, and search indexing.</p><table tabindex="0"><thead><tr><th>Name</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>Unique Content Identifier</td><td><code>$canonical_identifier</code></td><td>This is the unique identifier for content that will help Branch dedupe across many instances of the same thing. Suitable options include a website with pathing, or a database with identifiers for entitie</td></tr><tr><td>Canonical URL</td><td><code>$canonical_url</code></td><td>The corresponding web URL for the in-app content</td></tr><tr><td>Publicly Indexable</td><td><code>$publicly_indexable</code></td><td>Cannot modify here. Must be set by the Branch Universal Object.</td></tr><tr><td>Content Type Label</td><td><code>$content_type</code></td><td>This is a label for the type of content present. Apple recommends that you use uniform-type identifier as described here.</td></tr><tr><td>Content Expiration Date</td><td><code>$exp_date</code></td><td>Expiry date for the content and any associated link data. Represented as UTC epoch millisecond.</td></tr></tbody></table><h4 id="deepview-templates" tabindex="-1">Deepview templates <a class="header-anchor" href="#deepview-templates" aria-label="Permalink to &quot;Deepview templates&quot;">​</a></h4><p>Templates for Deepviews on iOS and Android.</p><table tabindex="0"><thead><tr><th>Name</th><th>Key</th><th>Definition</th></tr></thead><tbody><tr><td>iOS Passive Deepview Template</td><td><code>$ios_passive_deepview</code></td><td>The name of the Deepview template to use for iOS.</td></tr><tr><td>Android Passive Deepview Template</td><td><code>$android_passive_deepview</code></td><td>The name of the Deepview template to use for Android.</td></tr></tbody></table><h4 id="custom-data" tabindex="-1">Custom data <a class="header-anchor" href="#custom-data" aria-label="Permalink to &quot;Custom data&quot;">​</a></h4><p>Create custom keys to pass any custom data to be read inside your app. For example:</p><table tabindex="0"><thead><tr><th>Custom key (example)</th><th>Custom value (example)</th><th>Custom usage (example)</th></tr></thead><tbody><tr><td>random</td><td>123</td><td>Sending random information to your app.</td></tr></tbody></table><h3 id="link-appearance" tabindex="-1">Link appearance <a class="header-anchor" href="#link-appearance" aria-label="Permalink to &quot;Link appearance&quot;">​</a></h3><p>Customize the appearance of your Branch Short Link.</p><table tabindex="0"><thead><tr><th>Key</th><th>Default</th><th>Usage</th></tr></thead><tbody><tr><td><code>alias</code></td><td>none</td><td>Specify a link alias to replace of the standard encoded short URL (e.g. <code>https://example.app.link/aQXXDHaxKF</code> -&gt; <code>https://example.app.link/october-campaign</code> or <code>https://example.app.link/product/id1234</code>). Link aliases must be unique per app (a <code>400 error</code> will occur if you create an alias already taken). Also note that we don&#39;t currently support single character path segments after the domain (<code>/a/</code>, <code>/b/</code>, <code>/c/</code>, etc).</td></tr></tbody></table><h3 id="other-reserved-keys" tabindex="-1">Other reserved keys <a class="header-anchor" href="#other-reserved-keys" aria-label="Permalink to &quot;Other reserved keys&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Usage</th></tr></thead><tbody><tr><td><code>access_token</code> or <code>AccessToken</code></td><td>Used by Branch to determine if a deep link is a valid Branch link or not.</td></tr><tr><td><code>auth_token</code>or <code>AuthToken</code></td><td>Used by Branch to determine if a deep link is a valid Branch link or not.</td></tr><tr><td><code>data</code></td><td>Used by Branch to contain top-level link information. If this parameter is added to a Branch link via appending query params, it will be dropped. It can be safely used when creating a link manually via the dashboard.</td></tr><tr><td><code>password</code></td><td>If this parameter is added to a Branch link via appending query params, it will be dropped.</td></tr><tr><td><code>auth</code></td><td>If this parameter is added to a Branch link via appending query params, it will be dropped.</td></tr></tbody></table><h3 id="reserved-prefixes" tabindex="-1">Reserved prefixes <a class="header-anchor" href="#reserved-prefixes" aria-label="Permalink to &quot;Reserved prefixes&quot;">​</a></h3><p>Branch adds prefixes to each deep link data key to explain the key. You will see this added to the beginning of the different types of keys below.</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Usage</th></tr></thead><tbody><tr><td><code>$</code></td><td>Branch reserved keyword.</td></tr><tr><td><code>~</code></td><td>Branch analytical data.</td></tr><tr><td><code>+</code></td><td>Branch added values.</td></tr></tbody></table><h2 id="read-deep-links" tabindex="-1">Read deep links <a class="header-anchor" href="#read-deep-links" aria-label="Permalink to &quot;Read deep links&quot;">​</a></h2><p>Deep link data gets sent from your link to your app integration.</p><h3 id="data-structure" tabindex="-1">Data structure <a class="header-anchor" href="#data-structure" aria-label="Permalink to &quot;Data structure&quot;">​</a></h3><p>Example deep link data structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>        &quot;randomized_bundle_token&quot;: &quot;427469360685348303&quot;,</span></span>
<span class="line"><span>        &quot;link&quot;: &quot;https://example.app.link?%24randomized_bundle_token=427469360685348303&quot;,</span></span>
<span class="line"><span>        &quot;session_id&quot;: &quot;429691081177874743&quot;,</span></span>
<span class="line"><span>        &quot;data&quot;: {</span></span>
<span class="line"><span>        &quot;$canonical_identifier&quot;: &quot;item/1503684554354.28&quot;,</span></span>
<span class="line"><span>        &quot;$canonical_url&quot;: &quot;https://example.com/home?utm_campaign=test&amp;deeplink=value&quot;,</span></span>
<span class="line"><span>        &quot;$desktop_url&quot;: &quot;http://example.com/home&quot;,</span></span>
<span class="line"><span>        &quot;$randomized_bundle_token&quot;: &quot;427469360685348303&quot;,</span></span>
<span class="line"><span>        &quot;$og_description&quot;: &quot;My Content Description&quot;,</span></span>
<span class="line"><span>        &quot;$og_image_url&quot;: &quot;http://lorempixel.com/200/200/&quot;,</span></span>
<span class="line"><span>        &quot;$og_title&quot;: &quot;46D6D28E-0390-40E4-A856-BD74F34D24C8&quot;,</span></span>
<span class="line"><span>        &quot;$publicly_indexable&quot;: 1,</span></span>
<span class="line"><span>        &quot;+click_timestamp&quot;: 1503684563,</span></span>
<span class="line"><span>        &quot;+clicked_branch_link&quot;: true,</span></span>
<span class="line"><span>        &quot;+is_first_session&quot;: false,</span></span>
<span class="line"><span>        &quot;+match_guaranteed&quot;: true,</span></span>
<span class="line"><span>        &quot;custom&quot;: &quot;blue&quot;,</span></span>
<span class="line"><span>        &quot;random&quot;: &quot;FE848A5B-78F7-42EC-A253-9F795FE91692&quot;,</span></span>
<span class="line"><span>        &quot;added&quot;: &quot;1503684554354.33&quot;,</span></span>
<span class="line"><span>        &quot;~campaign&quot;: &quot;new launch&quot;,</span></span>
<span class="line"><span>        &quot;~channel&quot;: &quot;facebook&quot;,</span></span>
<span class="line"><span>        &quot;~creation_source&quot;: 3,</span></span>
<span class="line"><span>        &quot;~feature&quot;: &quot;sharing&quot;,</span></span>
<span class="line"><span>        &quot;~id&quot;: 429691043152332059,</span></span>
<span class="line"><span>        &quot;~referring_link&quot;: &quot;https://example.app.link/X7OsnWv9TF&quot;,</span></span>
<span class="line"><span>        &quot;~stage&quot;: &quot;new person&quot;,</span></span>
<span class="line"><span>        &quot;~tags&quot;: [</span></span>
<span class="line"><span>        &quot;one&quot;,</span></span>
<span class="line"><span>        &quot;two&quot;</span></span>
<span class="line"><span>        ]</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        }</span></span></code></pre></div><h3 id="callback-values" tabindex="-1">Callback values <a class="header-anchor" href="#callback-values" aria-label="Permalink to &quot;Callback values&quot;">​</a></h3><p>Additional properties read from the <code>initSession</code> within your app and <a href="./web-sdk-overview.html">website</a> integrations.</p><table tabindex="0"><thead><tr><th>Key</th><th>Usage</th></tr></thead><tbody><tr><td><code>~id</code></td><td>Automatically generated 18 digit ID number for the link that drove the install/open, if present (0 for dynamic and 3P links).</td></tr><tr><td><code>~referring_link</code></td><td>The referring link that drove the install/open, if present.</td></tr><tr><td><code>~creation_source</code></td><td>Where the link was created (<code>0</code> API\u2028, <code>1</code> Short Link, <code>2</code> SDK, <code>3</code> iOS SDK\u2028, <code>4</code> Android SDK\u2028, <code>5</code> Web SDK, <code>6</code> Dynamic, <code>7</code> Third party).</td></tr><tr><td><code>+match_guaranteed</code></td><td>If the match was made with 100% accuracy.</td></tr><tr><td><code>+referrer</code></td><td>The referrer for the link click, if a link was clicked.</td></tr><tr><td><code>+is_first_session</code></td><td><code>true</code> if first session (install), <code>false</code> if any other session (open) or if it did not previously exist in the Branch Link Graph. Default is <code>false</code>.</td></tr><tr><td><code>+clicked_branch_link</code></td><td>Whether or not the user clicked a Branch link that triggered this session. Default is <code>false</code>.</td></tr><tr><td><code>+non_branch_link</code></td><td>App was opened from a non Branch link (third party, invalid Branch deep link, or Branch key mismatch).</td></tr></tbody></table><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><h3 id="short-links-1" tabindex="-1">Short Links <a class="header-anchor" href="#short-links-1" aria-label="Permalink to &quot;Short Links&quot;">​</a></h3><details><summary>Why are some Short Link thumbnails not shown in WhatsApp?</summary><p>The most common issue with Short Links not rendering thumbnail previews in WhatsApp is the image file size being too large. Although Facebook supports the display of Open Graph images <a href="https://developers.facebook.com/docs/sharing/webmasters/images/#images-in-link-shares" target="_blank" rel="noreferrer">up to 8 MB</a> in size, their WhatsApp product appears to have different, undocumented size limitations. We&#39;ve seen that WhatsApp generally displays thumbnail previews for images up to 300 KB.</p><p>If your image file is larger than 300 KB, try reducing the image file size by adjusting your image dimensions or compression settings.</p></details><details><summary>Can I see the stats for links created using the API or SDK in Branch?</summary><p>Viewing Individual Link level stats for API/SDK created links is currently not available. Aggregate Stats can be observed in Branch by filtering with link analytics tags.</p></details><details><summary>Why aren’t my Short Links showing up in Branch?</summary><p>The Short Links section in Branch shows links that were generated in Branch. API/SDK-generated links are not visible in Branch.</p><p>If the Short Link you are looking for does not appear in Branch, it’s possible that the link wasn’t fetched in the first search. You will have to click on “Load More” at the bottom of the page, you should then be able to see the link pop up if it still exists.</p></details><details><summary>Why is my Short Link redirection not working as expected?</summary><p>If the Short Link redirection is not working as expected, we recommend trying to debug the link first to see if it is set up correctly.</p><ol><li>To debug a Short Link, you can go to <strong>Short Link</strong> &gt; <strong>Select a link</strong> and click on the ellipses, then click <strong>Debug</strong>.</li><li>On the Debug page, check the <strong>Link Details</strong> and the <strong>Link Routing Debugger</strong> section.</li></ol><p>You can also debug a link by adding debug=1 at the end of the link as a query parameter. For example: <a href="https://branchster.app.link/share-with-friends7**?debug=1" target="_blank" rel="noreferrer">https://branchster.app.link/share-with-friends7**?debug=1</a></p></details><details><summary>How can I create a Short Link for Snapchat?</summary><p>Snap won&#39;t let you attach redirecting links to stories. The following workaround disables the redirects until you get the link attached, and then re-enables them after you create your story.</p><ol><li><p>Create your Short Link to be attached to your Snap story.</p></li><li><p>On the Configure Options section, do the following:</p><ol><li>Add the key $always_deeplink, and the value of false in the <strong>Deep Linking</strong> tab.</li><li>Enable a Deepview on the iOS platform in the <strong>Redirects</strong> tab.</li></ol></li><li><p>Attach this link to your Snap story.</p></li><li><p>Come back and edit the Short Link to:</p><ol><li>Delete the $always_deeplink key/value from the <strong>Deep Linking</strong> tab.</li><li>Remove the Deepview on iOS in the <strong>Redirects</strong> tab.</li></ol></li></ol></details><details><summary>Does a Branch-generated QR code have an expiration date?</summary><p>No, QR codes do not have an expiration date. The QR code has a Short Link behind it. As long as the Short Link is active, the QR code will continue to work. Short Links will always be active if not deleted or archived. However, if you change the link domain (***.<a href="http://app.link" target="_blank" rel="noreferrer">app.link</a>) of your Branch app, all Short Links and the QR codes created with the old domain will stop working.</p></details><details><summary>Why do I have to click on &#39;Load More&#39; to find my link when searching Short Links?</summary><p>The dashboard only loads the last 500 Short Links. If the link that you are searching for is not part of these 500 links, click &#39;Load More&#39; in order to continue searching.</p><p>You can also load the Short Link directly, by going to the following URL with the corresponding Short Link ID appended to the end.</p><p><a href="https://dashboard.branch.io/quick-links/qlc/config/" target="_blank" rel="noreferrer">https://dashboard.branch.io/quick-links/qlc/config/</a>[Short Link ID]</p></details><details><summary>Are the number of &#39;Opens&#39; included in the number of &#39;Installs&#39; reported in Branch?</summary><p>Opens are not included in installs. If a user who already has the app clicks on the link and opens the app, it is counted as an open. If the app is not installed, the user is taken to the app/play store to install the app. The first time they open the app after the install is counted as an install.</p></details><details><summary>Can updating the Social Media Descriptors affect an app’s ranking in app store searches?</summary><p>Updating the Social Media descriptors will only change the Image and description associated with the link, will not have any impact on the app&#39;s search ranking.</p><p>These values will be updated next time the link is scrapped by the respective platform.</p></details><details><summary>Does Branch over-write UTM parameters if they are already detected in a link?</summary><p>When you use Branch links for redirecting users to a web URL, Branch automatically passes through any values from the following Branch link analytics tags as UTM parameters [~campaign -&gt; utm_campaign, ~channel -&gt; utm_source, ~feature -&gt; utm_medium]. However, If these UTM parameters are already detected on the URLs being redirected to, Branch will not overwrite them unless you have disabled the &#39;Analytics mapping with UTM&#39; setting on your Branch dashboard, which is already enabled by default</p><p>To view this setting, navigate to <strong>Configuration</strong> &gt; <strong>Advanced Settings</strong> in Branch.</p></details><details><summary>How long does it take for new images to appear on social media preview once updated?</summary><p>Branch will update the link &#39;og&#39; parameters immediately after it is updated. However how the social media descriptors show up on a platform are controlled by the platform. Different platforms handle these links in different ways, the platform might scrape the link everytime it is shared and the image might get refreshed immediately. However in most cases the link is not scraped regularly hence you might see a time lag before the image is updated for the link. If you are sharing on Facebook owned platforms you can manually scrape the link by visiting <a href="https://developers.facebook.com/tools/debug/" target="_blank" rel="noreferrer">https://developers.facebook.com/tools/debug/</a></p><p>Please note that the <code>$og_image_url</code> social preview feature is reserved for paid Branch accounts with a dedicated contract. If you do not have a paid Branch account, you will not see this feature in Branch.</p></details><details><summary>Why am I unable to find my link in the Short Links Section?</summary><p>Branch only shows you the last 500 Short Links created. You can access the next 500 Short Links by clicking on <strong>Load More</strong> at the end of the list.</p><p>Alternatively you can directly open the Short Link by navigating to the Short Link appended by the following parameters on a browser where you are signed in to Branch.</p><ul><li>To edit the link append ?edit=1</li><li>To view stats append ?stats=1</li><li>To debug the link append ?debug=1</li></ul><p>For example, if you want to edit <a href="https://example.app.link/testlink" target="_blank" rel="noreferrer">https://example.app.link/testlink</a>, try opening <a href="https://example.app.link/testlink?edit=1" target="_blank" rel="noreferrer">https://example.app.link/testlink?edit=1</a>.</p></details><details><summary>How are Short Links different from Ad Links?</summary><h4 id="functionality" tabindex="-1">Functionality <a class="header-anchor" href="#functionality" aria-label="Permalink to &quot;Functionality&quot;">​</a></h4><p>Functionally, Short Links and Ad Links work the same -- they both attribute in the same fashion (outside of the iOS ATT restrictions -- Short Links are “owned” links so these can still attribute downstream data) and route users in the same way to the destinations set up on the links.</p><p><a href="https://help.branch.io/v1/docs/ad-links" target="_blank" rel="noreferrer">Ad Links</a> are primarily designed for working with ad partners, so they’ll include a $3p value that designates the specific ad partner, and for integrated partners, they’ll include a much longer URL string that includes macros for the partner to pass through dynamic values like campaign name, etc. Additionally, Ad Links will automatically implement ATT-compliant behavior on iOS. <a href="https://help.branch.io/faq/docs/how-do-we-configure-a-non-ads-link-to-use-branchs-att-compliant-behavior" target="_blank" rel="noreferrer">This is not the case for Short Links</a>.</p><p><a href="https://help.branch.io/v1/docs/create-quick-links" target="_blank" rel="noreferrer">Short Links</a> are for “owned” placements (non-paid-ads use cases in general) and cases where the link may be visible, and Ad Links are designed for paid ads where users aren’t expected to see the link itself as well as where dynamic data is expected to be passed.</p><p>For a list of what Branch Link to use for a specific use case, see below:</p><table tabindex="0"><thead><tr><th>Branch Link</th><th>Use Cases</th></tr></thead><tbody><tr><td>Short Link</td><td>- Quick QR Code generator (via Branch Dashboard). - Custom Vanity/Alias Link. ex. <code>branchster.app.link/discount2022\`\`df</code></td></tr><tr><td>Ad Link</td><td>Ad Partner Campaign. ex. Facebook Ad Link: <code>https://branchster.app.link/J9g9yuoTPqb?%243p=a_facebook&amp;%24deeplink_no_attribution=true</code></td></tr></tbody></table><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Branch Ad Link creation is included in our Performance Essentials <a href="https://help.branch.io/docs/products" target="_blank" rel="noreferrer">product tier</a>, while access to the <a href="https://help.branch.io/v1-api/apidocs/quick-links-api" target="_blank" rel="noreferrer">Short Links API</a> is limited to Engagement Pro customers.</p></details><details><summary>Is there a way to split clicks and events for a link between a direct click and a QR code scan?</summary><p>It is not possible to differentiate between a direct click and a click through QR code scan as-is, however you can track direct clicks vs. scans by modifying the link for one (or both) mediums by using Analytics Tags.</p><p>For example, if your Short Link is <a href="https://example.app.link/test" target="_blank" rel="noreferrer">https://example.app.link/test</a>, you can publish the link with the tag noQR to see metrics between direct clicks and QR code scanned clicks: <a href="https://example.app.link/test?~tags=noQR" target="_blank" rel="noreferrer">https://example.app.link/test?~tags=noQR</a></p></details><h3 id="troubleshooting-deep-links" tabindex="-1">Troubleshooting deep links <a class="header-anchor" href="#troubleshooting-deep-links" aria-label="Permalink to &quot;Troubleshooting deep links&quot;">​</a></h3><details><summary>Can I deep link from another app into my app?</summary><p>Yes, you can link from another app into your app, and only your app needs the Branch SDK integrated.</p><p>There are 3 ways to embed links:</p><ol><li>Embed Short Link from the target app’s dashboard.</li><li>Use the Deep Linking API to create a link with the target app’s API key, making sure to send your API request early enough to account for response time.</li><li>Programmatically build the link as a <code>String</code>, starting with target app’s domain (i.e. <a href="https://example.app.link" target="_blank" rel="noreferrer">https://example.app.link</a>), and append deep link keys as encoded query parameters.</li></ol><p>Then, to execute in-app clicks:</p><p><strong>For iOS</strong></p><p>Call <code>UIApplication.shared.open()</code> on the link</p><p><strong>For Android</strong></p><p>Insert link into an Intent:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Intent intent = new Intent(Intent.ACTION_VIEW); intent.setData(Uri.parse(yourUrl));</span></span>
<span class="line"><span>startActivity(intent);</span></span></code></pre></div></details><details><summary>Why do my deep links not open my app?</summary><ul><li>Make sure you are clicking on a deep link (e.g. <a href="https://example.app.link/fzmLEhobLD" target="_blank" rel="noreferrer">https://example.app.link/fzmLEhobLD</a>)</li><li>Make sure you are not pasting a deep link in the address bar (in most cases, deep links must be clicked on)</li><li>Make sure the deep link is not wrapped (e.g. <a href="https://bit.ly/2yz3b8D" target="_blank" rel="noreferrer">https://bit.ly/2yz3b8D</a> instead of <a href="https://example.app.link/fzmLEhobLD" target="_blank" rel="noreferrer">https://example.app.link/fzmLEhobLD</a>)</li><li>Make sure you have configured your Branch and your app</li><li>Make sure the Branch key in your app matches the Branch key <a href="https://help.branch.io/v1/docs/creating-a-deep-link#view-deep-link-data" target="_blank" rel="noreferrer">in your deep link</a></li><li>Make sure you have not <a href="https://help.branch.io/developers-hub/docs/ios-troubleshooting#re-enable-universal-linking" target="_blank" rel="noreferrer">disabled universal linking on iOS</a></li><li>Make sure you understand the <a href="https://help.branch.io/v1/docs/creating-a-deep-link#default-link-behavior" target="_blank" rel="noreferrer">expected behavior of deep links</a></li><li>Make sure the deep link domain matches your <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">link domain</a> (e.g. link domain = <a href="http://example.app.link" target="_blank" rel="noreferrer">example.app.link</a>, deep link = <a href="https://example.app.link/fzmLEhobLD" target="_blank" rel="noreferrer">https://example.app.link/fzmLEhobLD</a>)</li></ul></details><details><summary>How do I view deep link data?</summary><p>Add <code>?debug=1</code> to the end of your deep link.</p><p>For example: <a href="https://example.app.link/aQXXDHaxKF?debug=1" target="_blank" rel="noreferrer">https://example.app.link/aQXXDHaxKF?debug=1</a></p></details><details><summary>How do I view deep link stats?</summary><p>Add <code>?stats=1</code> to the end of your deep link.</p><p>For example: <a href="https://example.app.link/aQXXDHaxKF?stats=1" target="_blank" rel="noreferrer">https://example.app.link/aQXXDHaxKF?stats=1</a></p></details><details><summary>How do I deep link effectively in China?</summary><p>We have found that our links don’t work with some Chinese ISPs. Here’s a list of the ones we have tested:</p><ul><li>China Mobile: Works as expected</li><li>Chine Net: Works as expected</li><li>Great Wall: Timeout error, ERR_TIMED_OUT on link response</li></ul></details><details><summary>How do I use Branch links in Snapchat Stories on iOS?</summary><p>Snap won&#39;t let you attach redirecting links to stories. The following work around disables the redirects until you get the link attached, and then re-enables them after you create your story.</p><ol><li><p>Create your Short Link to be attached to your Snap story</p></li><li><p>On the Configure Options section, do the following:</p><ol><li>Add the key <code>$always_deeplink</code>, and the value of <code>false</code> in the Deep Linking tab</li><li>Enable a Deepview on the iOS platform in the Redirects tab</li></ol></li><li><p>Attach this link to your Snap story</p></li><li><p>Come back and edit the Short Link to:</p><ol><li>Delete the <code>$always_deeplink</code> key/value from the Deep Linking tab</li><li>Remove the Deepview on iOS in the Redirects tab</li></ol></li></ol></details><details><summary>How do I fix the following error: “URL doesn’t pass security test”?</summary><p>The error message, “URL doesn’t pass security tests,” can show up when the link that you are trying to use as a redirection URL does not match the redirection allowlist set for your app. For example, Branch can create custom allowlists where links created for your app can only redirect to *.<a href="http://example.com" target="_blank" rel="noreferrer">example.com</a>.</p><p>If you try to create a link that redirects to any other domain other than *.<a href="http://example.com" target="_blank" rel="noreferrer">example.com</a>, you will see this error message and the link will not be created.</p><p>You can update your redirection allowlist in Branch. Read our <a href="https://help.branch.io/docs/advanced-link-configuration#redirect-allowlist" target="_blank" rel="noreferrer">Advanced Link Configuration</a> article to learn how.</p></details><details><summary>Why can’t access\\_token and auth\\_token be used as query parameters for long links?</summary><p><code>access_token</code> and <code>auth_token</code> (along with <code>AccessToken</code> and <code>AuthToken</code>) are <a href="https://help.branch.io/v1/docs/creating-a-deep-link" target="_blank" rel="noreferrer">reserved keys</a> used to determine if a deep link is a valid Branch link. Attempting to use these names as query parameters could yield unexpected results, so we don&#39;t allow their use in long URLs in order to prevent data collisions.</p></details><h3 id="nativelink" tabindex="-1">NativeLink <a class="header-anchor" href="#nativelink" aria-label="Permalink to &quot;NativeLink&quot;">​</a></h3><details><summary>Will NativeLink show for users with the app installed?</summary><p>No, NativeLink should not show for users who have the app installed because the app should just open up automatically via Universal Link rather than going through the web redirect.</p></details><details><summary>Will NativeLink override my existing Branch Deepviews?</summary><p>No, by default it should not override the existing Branch Deepview.</p><p>The only scenario where it would override the existing Deepview is if you have &quot;$ios_nativelink&quot;=true is set in the link parameters.</p></details>`,99)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
